function run(nomeUsuario) {
  var nome = (nomeUsuario || '').trim();
  if (!nome) { return JSON.stringify({valido: false, motivo: 'vazio'}); }
  var regex = /^[a-zA-Z\u00C0-\u017E\s]+$/;
  if (!regex.test(nome)) { return JSON.stringify({valido: false, motivo: 'caracteres_invalidos'}); }
  return JSON.stringify({valido: true});
}

function run(idadeUsuario) {
  var str = (idadeUsuario || '').trim();
  var num = parseInt(str, 10);
  if (!str || isNaN(num) || num <= 0 || String(num) !== str) {
    return JSON.stringify({valido: false});
  }
  return JSON.stringify({valido: true, idade: num});
}

function run() {
  var tipo = Math.random() < 0.5 ? 'filme' : 'serie';
  var framesFilme = [
    'Já que você gosta dos dois, hoje vou te recomendar um filme! 🎬',
    'Que ótimo gosto! Sendo assim, vou sortear... e saiu FILME! 🍿',
    'Como você é aberto a qualquer opção, deixa eu escolher por você: vamos de filme hoje! 🎬'
  ];
  var framesSerie = [
    'Já que você gosta dos dois, hoje vou te recomendar uma série! 📺',
    'Que ótimo gosto! Sendo assim, vou sortear... e saiu SÉRIE! 📺',
    'Como você é aberto a qualquer opção, deixa eu escolher por você: vamos de série hoje! 📺'
  ];
  var lista = tipo === 'filme' ? framesFilme : framesSerie;
  var msg = lista[Math.floor(Math.random() * lista.length)];
  return JSON.stringify({ tipo: tipo, mensagem: msg });
}

function run(entityGenero, generoInput) {
  var genero = (entityGenero || generoInput || 'drama').trim();
  var generoNorm = genero.toLowerCase()
    .replace(/[àáâãä]/g,'a').replace(/[èéêë]/g,'e')
    .replace(/[ìíîï]/g,'i').replace(/[òóôõö]/g,'o')
    .replace(/[ùúûü]/g,'u').replace(/[çÇ]/g,'c');
  var mapa = {
    'acao':    ['Die Hard', 'Mad Max: Fury Road', 'The Dark Knight', 'Heat', 'John Wick'],
    'comedia': ['The Hangover', 'Home Alone', 'Groundhog Day', 'Mrs. Doubtfire', 'Superbad'],
    'drama':   ['The Shawshank Redemption', 'Forrest Gump', 'The Godfather', 'Goodfellas', 'Schindlers List'],
    'terror':  ['The Shining', 'Get Out', 'A Quiet Place', 'Hereditary', 'It'],
    'suspense':['Inception', 'Memento', 'Shutter Island', 'Gone Girl', 'Se7en'],
    'romance': ['Titanic', 'The Notebook', 'La La Land', 'Before Sunrise', 'Casablanca'],
    'aventura':['Indiana Jones', 'Jurassic Park', 'The Princess Bride', 'The Mummy', 'Pirates of the Caribbean'],
    'animacao':['Toy Story', 'The Lion King', 'Up', 'Finding Nemo', 'Spirited Away'],
    'ficcao':  ['Interstellar', 'The Matrix', 'Blade Runner 2049', 'Arrival', 'Ex Machina']
  };
  var chave = 'drama';
  var palavras = Object.keys(mapa);
  for (var i = 0; i < palavras.length; i++) {
    if (generoNorm.indexOf(palavras[i]) >= 0 || palavras[i].indexOf(generoNorm) >= 0) {
      chave = palavras[i]; break;
    }
  }
  var filmes = mapa[chave];
  var br = String.fromCharCode(10);
  var texto = 'Filmes de ' + genero + ':' + br + br;
  for (var j = 0; j < filmes.length; j++) {
    texto += (j+1) + '. ' + filmes[j] + br;
  }
  texto += br + 'Digite o nome exato do filme que deseja consultar:';
  return texto;
}

