function run() {
  var series = [
    'Breaking Bad', 'Stranger Things', 'Game of Thrones', 'Dark',
    'The Last of Us', 'The Bear', 'Better Call Saul', 'Chernobyl',
    'Severance', 'The Wire'
  ];
  var br = String.fromCharCode(10);
  var texto = 'Aqui vão algumas séries aclamadas para você escolher:' + br + br;
  for (var i = 0; i < series.length; i++) {
    texto += (i + 1) + '. ' + series[i] + br;
  }
  texto += br + 'Digite o nome ou o número da série que deseja consultar:';
  return texto;
}

function run(titulo, contexto, listaJSON) {
  var t = (titulo || '').trim();
  var num = parseInt(t, 10);
  if (isNaN(num) || String(num) !== t) return t;
  if (contexto === 'series' && num >= 1 && num <= 10) {
    var series = [
      'Breaking Bad', 'Stranger Things', 'Game of Thrones', 'Dark',
      'The Last of Us', 'The Bear', 'Better Call Saul', 'Chernobyl',
      'Severance', 'The Wire'
    ];
    return series[num - 1];
  }
  if (contexto === 'filmes' && num >= 1 && num <= 5) {
    try {
      var lista = JSON.parse(listaJSON || '[]');
      return lista[num - 1] || t;
    } catch(e) { return t; }
  }
  return t;
}

function run(omdbResponseBody) {
  var data;
  try { data = JSON.parse(omdbResponseBody); } catch(e) { return JSON.stringify({encontrado: false}); }
  if (!data || data.Response === 'False' || !data.Title) {
    return JSON.stringify({encontrado: false});
  }
  var tipo = data.Type === 'series' ? 'Serie' : data.Type === 'episode' ? 'Episodio' : 'Filme';
  return JSON.stringify({
    encontrado: true,
    titulo: data.Title || 'N/A',
    ano: data.Year || 'N/A',
    genero: data.Genre || 'N/A',
    diretor: data.Director || 'N/A',
    atores: data.Actors || 'N/A',
    sinopse: data.Plot || 'N/A',
    avaliacao: data.imdbRating || 'N/A',
    duracao: data.Runtime || 'N/A',
    pais: data.Country || 'N/A',
    tipo: tipo
  });
}

